#!/usr/bin/env node
/**
 * Pre-bakes every agent .md file and config .json file into a single
 * netlify/lib/agents-data.js module. Netlify's esbuild bundler then
 * inlines the data into each function, eliminating the race condition
 * we hit when 6 functions all tried to copy the same `included_files`
 * directory at once on Windows.
 *
 * Run as part of `npm run build` (wired in package.json).
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const here = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(here, '..');
const AGENTS_DIR = path.join(root, 'netlify', 'agents');
const CONFIG_DIR = path.join(root, 'netlify', 'config');
const OUT_PATH  = path.join(root, 'netlify', 'lib', 'agents-data.js');

function parseFrontmatter(raw) {
  const match = raw.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n([\s\S]*)$/);
  if (!match) return { frontmatter: {}, body: raw };
  const frontmatter = {};
  for (const line of match[1].split(/\r?\n/)) {
    const m = line.match(/^([A-Za-z_][\w-]*):\s*(.*)$/);
    if (!m) continue;
    let val = m[2].trim();
    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
      val = val.slice(1, -1);
    }
    frontmatter[m[1]] = val;
  }
  return { frontmatter, body: match[2].trim() };
}

const agents = {};
for (const file of fs.readdirSync(AGENTS_DIR).filter(f => f.endsWith('.md'))) {
  const raw = fs.readFileSync(path.join(AGENTS_DIR, file), 'utf8');
  const { frontmatter, body } = parseFrontmatter(raw);
  const name = frontmatter.name || path.basename(file, '.md');
  agents[name] = { frontmatter, systemPrompt: body };
}

const configs = {};
for (const file of fs.readdirSync(CONFIG_DIR).filter(f => f.endsWith('.json'))) {
  const raw = fs.readFileSync(path.join(CONFIG_DIR, file), 'utf8');
  const key = path.basename(file, '.json');
  configs[key] = JSON.parse(raw);
}

const output = `/**
 * AUTO-GENERATED by scripts/build-agents-bundle.mjs — do not edit.
 * Inlines all agent prompts and config JSONs so functions don't need
 * runtime fs access for these assets (which caused EBUSY races on Windows).
 */
export const AGENTS = ${JSON.stringify(agents, null, 2)};
export const CONFIGS = ${JSON.stringify(configs, null, 2)};
`;

fs.writeFileSync(OUT_PATH, output, 'utf8');
console.log(`✓ Wrote ${OUT_PATH} (${Object.keys(agents).length} agents, ${Object.keys(configs).length} configs)`);
